// Son 24 saatteki haberleri filtrele
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const recentNews = $input.all().filter(item => {
  const pubDate = new Date(item.json.pubDate || item.json.isoDate);
  return pubDate >= yesterday;
});

// Rastgele karıştır (çeşitlilik için)
const shuffled = recentNews.sort(() => Math.random() - 0.5);

// İlk 30 haberi al (Gemini filtrelemesi için)
const topNews = shuffled.slice(0, 30);

return topNews.map(item => ({
  json: {
    title: item.json.title,
    link: item.json.link,
    description: item.json.contentSnippet || item.json.description || '',
    pubDate: item.json.pubDate || item.json.isoDate,
    source: item.json.creator || item.json['dc:creator'] || 'Unknown'
  }
}));

// Tüm haberleri tek bir prompt'a hazırla
const allNews = $input.all();

const newsText = allNews.map((item, index) => {
  return `[${index + 1}]
Başlık: ${item.json.title}
Açıklama: ${item.json.description}
Kaynak: ${item.json.source}
---`;
}).join('\n\n');

return [{
  json: {
    newsText: newsText,
    allNews: allNews
  }
}];

